using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides a simulated web search tool for the research agent.
/// Replace the body of <see cref="SearchWebAsync"/> with a real search API
/// (e.g., Bing Web Search API) for production use.
/// </summary>
public static class WebSearchTool
{
    private static readonly HttpClient s_http = new();

    [Description("Searches the web for information on a given query and returns relevant results with titles, snippets, and URLs.")]
    public static async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query)
    {
        // Attempt a live search via the DuckDuckGo Instant Answer API (no key required).
        // Falls back to simulated results if the request fails.
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            using var response = await s_http.GetAsync(url);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadAsStringAsync();
            var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract / main answer
            var abstractText = root.GetProperty("AbstractText").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();

            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[Source: {abstractSource}]\nURL: {abstractUrl}\n{abstractText}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                int index = results.Count + 1;
                foreach (var topic in topics.EnumerateArray())
                {
                    if (index > 5) break;

                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;

                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add($"[{index}] {text}\nURL: {firstUrl}");
                        index++;
                    }
                }
            }

            if (results.Count > 0)
            {
                return $"Search results for \"{query}\":\n\n{string.Join("\n\n", results)}";
            }
        }
        catch
        {
            // Fall through to simulated results
        }

        return GenerateSimulatedResults(query);
    }

    private static string GenerateSimulatedResults(string query)
    {
        var q = query.ToLowerInvariant();
        return $"""
            Search results for "{query}":

            [1] Wikipedia: {query}
            URL: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}
            Snippet: {query} is a topic of significant interest spanning multiple disciplines. Key areas include historical development, current applications, and emerging trends.

            [2] Latest Research on {query} – Science Daily
            URL: https://www.sciencedaily.com/search/?keyword={Uri.EscapeDataString(q)}
            Snippet: Recent studies have revealed new insights into {q}. Researchers highlight breakthroughs in methodology and practical applications that are reshaping the field.

            [3] {query}: A Comprehensive Guide – MIT Technology Review
            URL: https://www.technologyreview.com/topic/{Uri.EscapeDataString(q)}
            Snippet: This guide covers fundamental concepts through cutting-edge developments in {q}, including expert analysis and real-world case studies.

            [4] The Impact of {query} on Industry – Harvard Business Review
            URL: https://hbr.org/topic/{Uri.EscapeDataString(q)}
            Snippet: Analysis of how {q} is transforming industries and economies, with data-driven insights and expert commentary on future directions.

            [5] {query}: Current Trends and Future Outlook – Nature
            URL: https://www.nature.com/subjects/{Uri.EscapeDataString(q)}
            Snippet: An overview of current trends in {q} research, highlighting recent discoveries and promising directions for future investigation.
            """;
    }
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides an in-memory notebook the agent uses to collect and review research findings.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note or key finding. Use this after each web search to record important information, including source URLs.")]
    public string SaveNote(
        [Description("The note content to save")] string content)
    {
        _notes.Add(content);
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieves all previously saved research notes so you can review findings before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        return string.Join("\n\n", _notes.Select((note, i) => $"--- Note #{i + 1} ---\n{note}"));
    }
}

