using System.ComponentModel;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides an in-memory notebook the agent uses to collect and review research findings.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note or key finding. Use this after each web search to record important information, including source URLs.")]
    public string SaveNote(
        [Description("The note content to save")] string content)
    {
        _notes.Add(content);
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieves all previously saved research notes so you can review findings before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        return string.Join("\n\n", _notes.Select((note, i) => $"--- Note #{i + 1} ---\n{note}"));
    }
}

