using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Chat client via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tools ---
var notebook = new NoteTakingTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchWebAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetAllNotes),
};

// --- Agent with system instructions ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your goal is to thoroughly research a topic provided by the user.

        Follow this workflow:
        1. Break the topic into 2-3 focused search queries.
        2. For each query, use the SearchWebAsync tool to find information.
        3. After each search, use SaveNote to record the key findings (include source URLs).
        4. Once you have gathered enough information (at least 3 searches), use GetAllNotes to
           review your collected findings.
        5. Produce a well-structured final summary that synthesizes all your notes.

        Your final summary should include:
        - An overview of the topic
        - Key findings organized by theme
        - Sources cited with URLs

        Be thorough but concise. Focus on factual, well-sourced information.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking tools",
    tools: tools);

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n📚 Researching: {topic}\n");
Console.WriteLine(new string('─', 60));

// --- Run the agent with streaming output ---
var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine("✅ Research complete.");

